mapper.select:
SELECT period_type, stat_year, stat_quarter, stat_month, period_label, staff_id, staff_no, staff_name, order_count, sales_amount, gross_profit, sales_rank FROM ( SELECT period_type, stat_year, stat_quarter, stat_month, period_label, staff_id, staff_no, staff_name, order_count, sales_amount, gross_profit, DENSE_RANK() OVER (ORDER BY sales_amount DESC) AS sales_rank FROM v_sales_performance WHERE period_type = #{periodType} AND stat_year = #{statYear}
AND stat_month = #{statMonth}
AND stat_quarter = #{statQuarter}
) t ORDER BY sales_rank ASC, staff_id ASC LIMIT #{topN}
